// 1. جلب البيانات القادمة من الـ AI Agent
const inputData = $input.item.json;

// التحقق الرئيسي لمنع توقف السير والتأكد من وجود حقل output
if (inputData && inputData.output) {
    const data = inputData.output;

    // =========================
    // 1. email_target processing
    // =========================
    let rawTarget = (data.email_target || "").toLowerCase();
    let finalTarget = "none";

    // =========================
    // 2. ID Safety (تنظيف ID)
    // =========================
    if (data.Metadata_Context && data.Metadata_Context.ID) {
        let parsedId = parseInt(
            data.Metadata_Context.ID.toString().replace(/\D/g, ''),
            10
        );
        data.Metadata_Context.ID =
            isNaN(parsedId)
                ? Math.floor(100000 + Math.random() * 900000)
                : parsedId;
    }

    // =========================
    // 3. Delete Handling
    // =========================
    let rawAction = (data.action_type || "create").toLowerCase();

    let deleteTarget = (
        data.delete_search_term ||
        data.target_decision_id ||
        "none"
    ).toString().trim();

    let deleteMode = (data.delete_mode || "none").toLowerCase();
    let deleteCount = parseInt(data.delete_count, 10);

    // حماية من القيم غير الصالحة
    if (isNaN(deleteCount) || deleteCount < 1) {
        deleteCount = 1;
    }

    if (rawAction === "delete") {

        // حذف آخر قرارات
        if (
            deleteTarget.toUpperCase().includes("LAST") ||
            deleteTarget.includes("آخر") ||
            deleteTarget.includes("اخر")
        ) {
            deleteTarget = "LAST";
            deleteMode = "last";
        }

        // حذف بواسطة ID
        else if (
            data.target_decision_id &&
            data.target_decision_id !== "none"
        ) {
            deleteMode = "id";
            deleteTarget = data.target_decision_id;
        }

        // حذف بواسطة بحث
        else if (
            data.delete_search_term &&
            data.delete_search_term !== "none"
        ) {
            deleteMode = "search";
            deleteTarget = data.delete_search_term;
        }
    }

    // =========================
    // 4. Email Target Classification
    // =========================
    let finalTarget = "none";

    if (
        rawTarget.includes("metadata") ||
        rawTarget.includes("context") ||
        rawTarget.includes("قرار")
    ) {
        finalTarget = "metadata";

    } else if (
        rawTarget.includes("scoring") ||
        rawTarget.includes("درج") ||
        rawTarget.includes("تقييم")
    ) {
        finalTarget = "scoring";

    } else if (
        rawTarget.includes("analysis") ||
        rawTarget.includes("تحليل") ||
        rawTarget.includes("تشخيص")
    ) {
        finalTarget = "analysis";

    } else if (
        rawTarget.includes("recommend") ||
        rawTarget.includes("توصي") ||
        rawTarget.includes("خطة")
    ) {
        finalTarget = "recommendation";

    } else if (
        rawTarget.includes("all") ||
        rawTarget.includes("كل") ||
        rawTarget.includes("الكامل")
    ) {
        finalTarget = "all";

    } else if (rawTarget !== "none" && rawTarget.includes("@")) {
        finalTarget = "all";
    }

    // =========================
    // 5. Message Formatting
    // =========================
    const formattedMessage = `
## 🧠 قرار: ${data.Metadata_Context?.Decision || 'غير محدد'}
---
📊 **البيانات التعريفية والتقييم:**
* **نوع القرار:** ${data.Metadata_Context?.Decision_Classification || '-'}
* **معرّف القرار (ID):** ${data.Metadata_Context?.ID || '-'}
* **التقييم الكمي الإجمالي:** ${data.Quantitative_Scoring?.Total_Score || '0'} من 14

📋 **خطة العمل التنفيذية (Action Plan):**
${data.Execution_Recommendation?.Action_Plan || '-'}

⚠️ **إدارة المخاطر والحلول البديلة:**
${data.Execution_Recommendation?.Risk_Mitigations || '-'}

💡 **التوصية النهائية:**
${data.Execution_Recommendation?.Recommendation || '-'}
`.trim();

    // =========================
    // 6. Final Output
    // =========================
    return [{
        json: {
            Metadata_Context: data.Metadata_Context,
            Quantitative_Scoring: data.Quantitative_Scoring,
            Qualitative_Analysis_Diagnosis: data.Qualitative_Analysis,
            Execution_Recommendation: data.Execution_Recommendation,

            message: formattedMessage,
            is_status_message: false,

            send_email_target: finalTarget,
            action_type: rawAction,

            delete_target: deleteTarget,
            delete_mode: deleteMode,
            delete_count: deleteCount
        }
    }];

} else {
    return [{
        json: {
            message: inputData.output || "لم يتم استخراج بيانات محددة.",
            is_status_message: true
        }
    }];
}

// جلب مصفوفة السطور القادمة من جوجل شيت
const rows = items; 
let reportContext = "إليك سجل العمليات والأحداث المسجلة في جدول البيانات لهذا الأسبوع:\n\n";

for (const row of rows) {
  const data = row.json;
  // تأكد من تطابق أسماء الأعمدة هنا مع الأسماء الحقيقية في الشيت الخاص بك
  reportContext += `- التاريخ: ${data.Date || 'غير محدد'} | المشروع: ${data.Category_Project || 'عام'} | العملية: ${data.Task_Operation || ''} | الحالة: ${data.Status || ''} | ملاحظات وعقبات: ${data.Notes_Issues || 'لا يوجد'}\n`;
}

// إرسال النص المدمج كعنصر رئيسي للعقدة التالية
return [{ json: { full_context: reportContext } }];
